  ('elementary-0489de64-moex-00250', 'elementary-0489de64', 'elementary-0489de64-moex-113-b3f42868', 'sub-elementary-0489de64-02', NULL, 'single_choice', '某列車與一輛從斜坡上跌落到鐵軌上的工程車相撞後出軌，造成人員傷亡慘重。事故發生後，某位脫困乘 客因被其他人拍到站在事故旁的邊坡，而被媒體誤報為「偷偷施工又見死不救的工人」，導致該名乘客被 誤解的網路鄉民肉搜與圍剿。從媒體識讀的角度檢視，何者最適合用來描述前述媒體報導所引發的現象？', '["媒體未善盡查證責任，報導內容出現不實的訊息", "媒體為搶收視率，以煽情的內容渲染大眾的情緒", "媒體形塑勞工負面刻板印象，加劇民眾對勞工的歧視", "媒體報導檢察官尚在調查的訊息，違反偵查不公開原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
